def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        complexity = 1.0
        extra_penalties = 0.0
        bonus = 1.0
        alternating_sum = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 8):
                penalty += (ratio ** (2 * k)) / (k**2 + 1)
                if k % 2 == 0:
                    penalty -= np.log(k + 1)
                else:
                    penalty += np.sqrt(k)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 3))
            score = (ratio ** 6) / 6 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            complexity = 1.0
            for z in range(1, 5):
                complexity *= (1 + z / (bins[i] + 2))
            score = score * decay / complexity
            if ratio % 2 < 1:
                score += np.sin(ratio) * 10
            priorities[i] = score
        elif 3 < ratio <= 5:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                alternating_sum += sign * (ratio ** x) / (x + 3)
            score = abs(alternating_sum) * 15
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 5))
                bonus += np.cos(y * ratio) / (y + 1)
            score *= decay * bonus
            priorities[i] = score
        elif 1 < ratio <= 3:
            temp = 0.0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 4)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 30 if ratio < 2 else 20
            complexity = 0.5
            for u in range(1, 6):
                complexity += np.exp(-u / ratio) / u
            score = abs(temp) * multiplier * complexity
            if ratio > 2.8:
                bonus = 0.0
                for m in range(1, 8):
                    bonus += (ratio ** m) / (m * 4 + 3)
                score += bonus * 3
            priorities[i] = score
        elif 0.2 < ratio <= 1:
            temp_score = 0.0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                else:
                    temp_score += (ratio ** p) / (p * 6)
            if ratio < 0.5:
                multiplier = 28
            elif ratio < 0.75:
                multiplier = 18
            else:
                multiplier = 10
            decay = 1.0
            for q in range(1, 8):
                decay *= (1 - 1 / (q + ratio * 2 + 1))
            score = abs(temp_score) * multiplier * decay
            if ratio > 0.65:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[i] = score
        elif 0 <= ratio <= 0.2:
            base = 0
            for r in range(1, 25):
                base += ((-1) ** r) * (ratio ** r) / (r + 1)
            multiplier = 35 if ratio == 0 else 40 - 150 * ratio
            complex_decay = 1.0
            for s in range(1, 5):
                complex_decay *= (1 - 1 / (s + ratio + 0.1))
            score = abs(base) * multiplier * complex_decay
            if ratio < 0.1:
                score *= 1.5
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                if bins[i] + z == 0:
                    continue
                factor *= (1 + z / (bins[i] + z))
            priorities[i] *= factor
            if bins[i] > 10:
                priorities[i] /= (bins[i] ** 0.1)
            if bins[i] < 3 and priorities[i] > 50:
                priorities[i] += np.log(bins[i] + 1) * 5
        else:
            priorities[i] = np.inf
    return priorities
